import React from 'react';
import { Link, useNavigate } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const isLoggedIn = !!localStorage.getItem('token');

  const handleLogout = () => {
    localStorage.clear();
    navigate('/');
  };

  return (
    <nav style={navStyle}>
      <div style={{ fontWeight: 'bold', fontSize: '1.5rem', color: '#1a1a1a' }}>
        📦 Vintage Vault
      </div>
      
      <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
        {isLoggedIn ? (
          <>
            <Link to="/marketplace" style={linkStyle}>Marketplace</Link>
            <Link to="/dashboard" style={linkStyle}>Dashboard</Link>
            <button onClick={handleLogout} style={logoutButtonStyle}>Logout</button>
          </>
        ) : (
          <Link to="/" style={linkStyle}>Login / Register</Link>
        )}
      </div>
    </nav>
  );
};

// Pastel-inspired professional styles
const navStyle = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '15px 40px',
  backgroundColor: '#fdfcf0', // Soft pastel cream
  borderBottom: '1px solid #eee',
  position: 'sticky',
  top: 0,
  zIndex: 1000
};

const linkStyle = {
  textDecoration: 'none',
  color: '#444',
  fontWeight: '500',
  fontSize: '1rem'
};

const logoutButtonStyle = {
  padding: '8px 15px',
  backgroundColor: '#ffedea', // Soft pastel red/pink
  color: '#d32f2f',
  border: '1px solid #ffcdd2',
  borderRadius: '5px',
  cursor: 'pointer'
};

export default Navbar;
